                // TODO(port): same as in pretailcall — offset 0 = first instruction.
                state.set_ci_savedpc(ci_idx, 0);

                // C: for (; narg < nfixparams; narg++) setnilvalue(s2v(L->top.p++))
                let mut narg = narg;
