fn get_local_name(p: &LuaProto, n: i32, pc: i32) -> Option<&[u8]> {
    // TODO(port): iterate p.locvars to find the n-th live variable at pc
    let _ = (p, n, pc);
    None
}

/// Gets the n-th local name from a Lua closure (for non-active function query).
